+    return {
+      ok: true,
+      commandId: command.id,
+      durationMs,
+      data,
+    } satisfies SweetLinkCommandResultSuccess;
+  } catch (error: unknown) {
+    const error_ = toError(error);
+    const durationMs = performance.now() - durationStart;
+    return {
+      ok: false,
+      commandId: command.id,
+      durationMs,
+      error: error_.message,
+      stack: error_.stack,
