+      readonly visibility?: 'any' | 'visible';
+      readonly timeoutMs?: number;
+    }
+  | {
+      readonly type: 'waitForIdle';
+      readonly timeoutMs?: number;
+      readonly frameCount?: number;
+    }
+  | {
+      readonly type: 'wait';
+      readonly ms: number;
