+    case 'waitForSelector': {
+      return typeof record.selector === 'string';
+    }
+    case 'waitForIdle': {
+      return true;
+    }
+    case 'wait': {
+      return typeof record.ms === 'number' && Number.isFinite(record.ms);
+    }
+    case 'script': {
+      return typeof record.code === 'string';
+    }
+    default: {
+      return false;
+    }
+  }
+};
