+function createTextSnippet(element: HTMLElement): string | null {
+  const text = element.innerText ?? element.textContent ?? '';
+  const trimmed = text.trim().replace(/\s+/g, ' ');
+  if (!trimmed) {
+    return null;
+  }
+  if (trimmed.length <= 60) {
+    return trimmed;
+  }
+  return `${trimmed.slice(0, 57)}…`;
