+function isVisible(rect: DOMRect, computed: CSSStyleDeclaration): boolean {
+  if (rect.width <= 1 || rect.height <= 1) {
+    return false;
+  }
+  if (computed.visibility === 'hidden' || computed.display === 'none' || Number.parseFloat(computed.opacity) < 0.05) {
+    return false;
+  }
+  return true;
+}
+
+function buildDomPath(element: HTMLElement): string {
+  const segments: string[] = [];
+  let current: HTMLElement | null = element;
+  while (current) {
+    const id = current.id ? `#${current.id}` : '';
+    const classes =
+      current.classList.length > 0
+        ? `.${[...current.classList].map((className) => className.replace(/\s+/g, '-')).join('.')}`
+        : '';
+    segments.unshift(`${current.tagName.toLowerCase()}${id}${classes}`.trim());
+    current = current.parentElement;
+  }
+  return segments.join(' > ');
+}

