+import { logDebugError } from '../util/errors';
+
+type NextDevtoolsToolResult =
+  | {
+      result?: {
+        content?: Array<{
+          type?: string;
+          text?: string;
+        }>;
+      };
+    }
+  | undefined;
+
+const ACCEPT_HEADER = 'application/json, text/event-stream';
+
+async function callNextDevtoolsTool(
+  origin: string,
+  toolName: string,
+  args: Record<string, unknown> = {}
+): Promise<NextDevtoolsToolResult> {
+  const controller = new AbortController();
+  const timeout = setTimeout(() => controller.abort(), 2500);
+  try {
+    const response = await fetch(`${origin}/_next/mcp`, {
+      method: 'POST',
+      headers: {
+        Accept: ACCEPT_HEADER,
+        'Content-Type': 'application/json',
+      },
+      body: JSON.stringify({
+        jsonrpc: '2.0',
+        id: `${Date.now()}`,
+        method: 'tools/call',
+        params: {
+          name: toolName,
+          arguments: args,
+        },
+      }),
+      signal: controller.signal,
+    });
+    if (!response.ok) {
+      return undefined;
+    }
+    const raw = await response.text();
+    const dataLine = raw
+      .split('\n')
+      .map((line) => line.trim())
+      .find((line) => line.startsWith('data:'));
+    if (!dataLine) {
+      return undefined;
+    }
+    const payload = dataLine.slice(5).trim();
+    if (!payload) {
+      return undefined;
+    }
+    return JSON.parse(payload);
+  } catch (error) {
+    logDebugError('Next DevTools call failed', error);
+    return undefined;
+  } finally {
+    clearTimeout(timeout);
+  }
+}
+
+export async function fetchNextDevtoolsErrors(targetUrl: string): Promise<string | null> {
+  let origin: string;
+  try {
+    origin = new URL(targetUrl).origin;
+  } catch {
+    return null;
+  }
+  const result = await callNextDevtoolsTool(origin, 'get_errors');
+  const content = result?.result?.content;
+  if (!Array.isArray(content) || content.length === 0) {
+    return null;
+  }
+  const textChunk = content.find((entry) => entry?.type === 'text' && typeof entry.text === 'string');
+  return textChunk?.text ?? null;
+}

