+import type { ChildProcess } from 'node:child_process';
+import { beforeEach, describe, expect, it, vi } from 'vitest';
+
+const spawnMock = vi.hoisted(() => vi.fn());
+
+vi.mock('node:child_process', () => ({
+  spawn: spawnMock,
+}));
+
+const codexModule = await import('../src/codex');
+const { runCodexImagePrompt, runCodexTextPrompt, analyzeConsoleWithCodex } = codexModule;
+
+type Listener = (...arguments_: any[]) => void;
+
+function createChild(): ChildProcess & { stdin: { write: ReturnType<typeof vi.fn>; end: ReturnType<typeof vi.fn> } } {
+  const listeners = new Map<string, Set<Listener>>();
+  const addListener = (event: string, listener: Listener) => {
+    const bucket = listeners.get(event);
+    if (bucket) {
+      bucket.add(listener);
+    } else {
+      listeners.set(event, new Set([listener]));
+    }
+  };
+
+  const child = {
+    stdin: {
+      write: vi.fn(),
+      end: vi.fn(),
+    },
+    on(event: string, listener: Listener) {
+      addListener(event, listener);
+      return this;
+    },
+    once(event: string, listener: Listener) {
+      const wrapper: Listener = (...args) => {
+        this.off(event, wrapper);
+        listener(...args);
+      };
+      return this.on(event, wrapper);
+    },
+    off(event: string, listener: Listener) {
+      listeners.get(event)?.delete(listener);
+      return this;
+    },
+    emit(event: string, ...args: unknown[]) {
+      const subscribers = listeners.get(event);
+      if (subscribers) {
+        for (const listener of subscribers) {
+          listener(...args);
+        }
+      }
+      return true;
+    },
+    removeAllListeners(event?: string) {
+      if (typeof event === 'string') {
+        listeners.delete(event);
+      } else {
+        listeners.clear();
+      }
+      return this;
+    },
+  } as ChildProcess & {
+    stdin: { write: ReturnType<typeof vi.fn>; end: ReturnType<typeof vi.fn> };
+    emit: (event: string, ...args: unknown[]) => boolean;
+  };
+
+  return child;
+}
+
