+    setImmediate(() => child.emit('close', 0));
+
+    const exitCode = await promise;
+    expect(exitCode).toBe(0);
+    expect(spawnMock).toHaveBeenCalledWith('codex', expect.arrayContaining(['-i', '/tmp/screenshot.jpg', '-']), {
+      stdio: ['pipe', 'inherit', 'inherit'],
